patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..9deb72243549 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,10 +8638,26 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0), X, 0), C -> fcmp oeq X, C
+      // When X is NaN, select returns 0, and fcmp oeq 0, C is false (same as fcmp oeq NaN, C)
+      // When X is ordered, select returns X, and fcmp oeq X, C is the comparison
+      if (Pred == FCmpInst::FCMP_OEQ) {
+        if (auto *CondFCmp = dyn_cast<FCmpInst>(LHSI->getOperand(0))) {
+          if (CondFCmp->getPredicate() == FCmpInst::FCMP_ORD) {
+            Value *X = nullptr;
+            Value *FCmpZero = nullptr;
+            if ((match(CondFCmp, m_FCmp(m_Value(X), m_AnyZeroFP())) ||
+                 match(CondFCmp, m_FCmp(m_AnyZeroFP(), m_Value(X)))) &&
+                ((LHSI->getOperand(1) == X && match(LHSI->getOperand(2), m_AnyZeroFP())) ||
+                 (LHSI->getOperand(2) == X && match(LHSI->getOperand(1), m_AnyZeroFP())))) {
+              return new FCmpInst(Pred, X, Op1, "", &I);
+            }
+          }
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;
-    case Instruction::FSub:
       if (LHSI->hasOneUse())
         if (Instruction *NV = foldFCmpFSubIntoFCmp(I, LHSI, RHSC, *this))
           return NV;

